import {
	AdminGetUserCommand,
	CognitoIdentityProviderClient,
} from '@aws-sdk/client-cognito-identity-provider';
import { getTenantContext, createResponse } from 'tenant-utils';

const validateInputParams = (event) => {
	return event.email.trim().length > 0 && event.apti.trim().length > 0;
};

const getUser = async (payload, cognito, userPoolId, tenantId) => {

	const command = new AdminGetUserCommand({
		Username: payload.email,
		UserPoolId: userPoolId,
	});
	try {
		const user = await cognito.send(command);
		console.log(`[Tenant: ${tenantId}] get user:`, user);
		return user;
	} catch (error) {
		console.log(`[Tenant: ${tenantId}] error in get user:`, error);
		console.log(`[Tenant: ${tenantId}] error code:`, error.code);
		throw error;
	}
}

// lambda for rest api /checkuser
export const handler = async (event) => {
	console.log(event);

	try {
		// Extract tenant context from request
		const tenantContext = await getTenantContext(event);
		console.log('Tenant context:', tenantContext);

		const payload = JSON.parse(event.body);

		if (validateInputParams(payload)) {
			const cognito = new CognitoIdentityProviderClient({
				region: process.env.AWS_REGION,
			});

			try {

				const user = await getUser(payload, cognito, tenantContext.userPoolId, tenantContext.tenantId);
				console.log(`[Tenant: ${tenantContext.tenantId}] find user:`, user);

				if (user) {
					return createResponse(400, { message: 'Username already exists' }, tenantContext.tenantId);
				}
			} catch (err) {
				console.error(`[Tenant: ${tenantContext.tenantId}] Error:`, err);

				if (err.code === 'UserNotFoundException' || err.message === 'User does not exist.') {
					return createResponse(200, { message: 'username is available' }, tenantContext.tenantId);
				}
				const error = err.message ? err.message : { message: "error while checking email signup" }
				return createResponse(400, error, tenantContext.tenantId);
			}
		} else {
			return createResponse(500, { message: 'incoming params error.' }, tenantContext.tenantId);
		}

	} catch (e) {
		console.log('Catch an error: ', e);
		
		// Try to get tenant ID for error response
		let tenantId = null;
		try {
			const tenantContext = await getTenantContext(event);
			tenantId = tenantContext.tenantId;
		} catch (tenantError) {
			console.log('Could not extract tenant ID for error response:', tenantError.message);
		}
		
		return createResponse(500, { message: 'check username error' }, tenantId);
	}
};
